class Solution:
    def removeAlmostEqualCharacters(self, word: str) -> int:
        operations = 0
        n = len(word)
        i = 0
        while i < n - 1:
            # Check if current and next character are almost-equal
            if abs(ord(word[i]) - ord(word[i + 1])) <= 1:
                # Change the next character to a non-almost-equal character
                operations += 1
                i += 2  # Skip the next character as it's now fixed
            else:
                i += 1
        return operations
